const PHRASAL_VERBS = [
  {id:'go-on',phrase:'go on',ipa:'ɡoʊ ɑn',meaning:'continuar; acontecer',separable:false,register:'neutral',freq:5,cls:'sage',ex:[{en:"Please go on with your story.",pt:"Por favor, continue."},{en:"What's going on here?",pt:"O que está acontecendo aqui?"},{en:"Life goes on.",pt:"A vida continua."}],trap:'Não confunda com "get on with" (relacionar-se bem).',similar:[{phrase:'carry on',meaning:'prosseguir (formal)'},{phrase:'keep on',meaning:'continuar fazendo'}]},
  {id:'come-back',phrase:'come back',ipa:'kʌm bæk',meaning:'voltar; retornar',separable:false,register:'neutral',freq:5,cls:'sage',ex:[{en:"Come back soon!",pt:"Volte logo!"},{en:"She came back from Paris yesterday.",pt:"Ela voltou de Paris ontem."},{en:"The trend is coming back.",pt:"A tendência está voltando."}],trap:'"Come back" é movimento para perto do falante; "go back" é para longe.',similar:[{phrase:'go back',meaning:'voltar (para longe do falante)'},{phrase:'return',meaning:'retornar (formal)'}]},
  {id:'find-out',phrase:'find out',ipa:'faɪnd aʊt',meaning:'descobrir; ficar sabendo',separable:true,register:'neutral',freq:5,cls:'sage',ex:[{en:"I found out the truth.",pt:"Eu descobri a verdade."},{en:"How did you find out?",pt:"Como você ficou sabendo?"},{en:"Let's find it out together.",pt:"Vamos descobrir juntos."}],trap:'"Find" é encontrar algo físico; "find out" é descobrir uma informação.',similar:[{phrase:'discover',meaning:'descobrir (formal)'},{phrase:'learn',meaning:'ficar sabendo'}]},
  {id:'pick-up',phrase:'pick up',ipa:'pɪk ʌp',meaning:'pegar; buscar (alguém); aprender informalmente',separable:true,register:'neutral',freq:5,cls:'sage',ex:[{en:"I'll pick you up at 8.",pt:"Eu te busco às 8."},{en:"She picked up Spanish quickly.",pt:"Ela aprendeu espanhol rápido."},{en:"Pick up the phone!",pt:"Atende o telefone!"}],trap:'Múltiplos sentidos contextuais. Brasileiros usam "buscar/aprender/atender" separadamente.',similar:[{phrase:'collect',meaning:'recolher (formal)'},{phrase:'fetch',meaning:'ir buscar (BrE)'}]},
  {id:'come-up',phrase:'come up',ipa:'kʌm ʌp',meaning:'surgir; aparecer (assunto)',separable:false,register:'neutral',freq:5,cls:'amber',ex:[{en:"Something came up at work.",pt:"Algo surgiu no trabalho."},{en:"This topic always comes up.",pt:"Esse assunto sempre vem à tona."},{en:"A new opportunity came up.",pt:"Uma nova oportunidade apareceu."}],trap:'"Come up" sozinho ≠ "come up with" (ter uma ideia). Atenção à preposição.',similar:[{phrase:'arise',meaning:'surgir (formal)'},{phrase:'come up with',meaning:'bolar uma ideia'}]},
  {id:'go-back',phrase:'go back',ipa:'ɡoʊ bæk',meaning:'voltar (para um lugar/situação anterior)',separable:false,register:'neutral',freq:5,cls:'sage',ex:[{en:"I want to go back home.",pt:"Quero voltar para casa."},{en:"Let's go back to the beginning.",pt:"Vamos voltar ao início."},{en:"This tradition goes back centuries.",pt:"Essa tradição remonta a séculos."}],trap:'Da perspectiva de quem está afastado do destino. Quem está no destino diz "come back".',similar:[{phrase:'return',meaning:'retornar (formal)'},{phrase:'revisit',meaning:'revisitar'}]},
  {id:'set-up',phrase:'set up',ipa:'sɛt ʌp',meaning:'montar; configurar; estabelecer',separable:true,register:'neutral',freq:5,cls:'sage',ex:[{en:"Let's set up a meeting.",pt:"Vamos marcar uma reunião."},{en:"He set up his own company.",pt:"Ele montou sua própria empresa."},{en:"Can you set this up for me?",pt:"Pode configurar isso pra mim?"}],trap:'Pode também significar "incriminar/armar para alguém": "He was set up".',similar:[{phrase:'establish',meaning:'estabelecer (formal)'},{phrase:'arrange',meaning:'organizar'}]},
  {id:'turn-out',phrase:'turn out',ipa:'tɝn aʊt',meaning:'acabar sendo; revelar-se',separable:false,register:'neutral',freq:5,cls:'amber',ex:[{en:"It turned out to be a great day.",pt:"Acabou sendo um ótimo dia."},{en:"He turned out to be a fraud.",pt:"Ele se revelou uma fraude."},{en:"How did it turn out?",pt:"Como acabou ficando?"}],trap:'Sentido idiomático — não é "virar para fora". Sempre indica resultado/revelação.',similar:[{phrase:'end up',meaning:'acabar em determinada situação'},{phrase:'prove to be',meaning:'mostrar-se (formal)'}]},
  {id:'put-on',phrase:'put on',ipa:'pʊt ɑn',meaning:'vestir; colocar; ligar',separable:true,register:'neutral',freq:5,cls:'sage',ex:[{en:"Put on your coat.",pt:"Coloque seu casaco."},{en:"Put the music on.",pt:"Ligue a música."},{en:"She put on weight.",pt:"Ela engordou."}],trap:'"Put on" (vestir = ação) ≠ "wear" (estar vestindo = estado). Brasileiros confundem.',similar:[{phrase:'wear',meaning:'usar/estar vestindo'},{phrase:'don',meaning:'vestir (literário)'}]},
  {id:'come-out',phrase:'come out',ipa:'kʌm aʊt',meaning:'sair; ser lançado; revelar-se',separable:false,register:'neutral',freq:5,cls:'sage',ex:[{en:"The book came out last month.",pt:"O livro foi lançado mês passado."},{en:"The sun came out.",pt:"O sol apareceu."},{en:"He came out as gay.",pt:"Ele se assumiu gay."}],trap:'Múltiplos sentidos contextuais — lançamento, revelação, surgimento.',similar:[{phrase:'be released',meaning:'ser lançado (formal)'},{phrase:'emerge',meaning:'emergir'}]},
  {id:'look-for',phrase:'look for',ipa:'lʊk fɔr',meaning:'procurar',separable:false,register:'neutral',freq:5,cls:'sage',ex:[{en:"I'm looking for my keys.",pt:"Estou procurando minhas chaves."},{en:"They're looking for a new house.",pt:"Eles procuram casa nova."},{en:"Look for the answer.",pt:"Procure a resposta."}],trap:'"Look for" (procurar) ≠ "look at" (olhar para) ≠ "look after" (cuidar de).',similar:[{phrase:'search for',meaning:'buscar (formal)'},{phrase:'seek',meaning:'buscar (literário)'}]},
  {id:'get-up',phrase:'get up',ipa:'ɡɛt ʌp',meaning:'levantar (da cama)',separable:false,register:'neutral',freq:5,cls:'sage',ex:[{en:"I get up at 6 AM.",pt:"Eu levanto às 6."},{en:"Get up! It's late.",pt:"Levante! Está tarde."},{en:"He got up from the chair.",pt:"Ele se levantou da cadeira."}],trap:'"Get up" é levantar; "wake up" é acordar (sair do sono). Ações distintas.',similar:[{phrase:'wake up',meaning:'acordar (do sono)'},{phrase:'rise',meaning:'levantar-se (formal)'}]},
  {id:'come-in',phrase:'come in',ipa:'kʌm ɪn',meaning:'entrar',separable:false,register:'neutral',freq:5,cls:'sage',ex:[{en:"Please come in.",pt:"Por favor, entre."},{en:"Come in and sit down.",pt:"Entre e sente-se."},{en:"The data came in this morning.",pt:"Os dados chegaram esta manhã."}],trap:'"Come in" = entrar (perspectiva de dentro). "Go in" = entrar (de fora).',similar:[{phrase:'enter',meaning:'entrar (formal)'},{phrase:'go in',meaning:'entrar (de fora)'}]},
  {id:'go-out',phrase:'go out',ipa:'ɡoʊ aʊt',meaning:'sair (de casa, com alguém); apagar (luz)',separable:false,register:'neutral',freq:5,cls:'sage',ex:[{en:"Let's go out tonight.",pt:"Vamos sair hoje à noite."},{en:"They've been going out for years.",pt:"Eles namoram há anos."},{en:"The lights went out.",pt:"As luzes se apagaram."}],trap:'"Going out with someone" = namorar. Sentido romântico distinto.',similar:[{phrase:'leave',meaning:'sair/partir'},{phrase:'date',meaning:'namorar'}]},
  {id:'point-out',phrase:'point out',ipa:'pɔɪnt aʊt',meaning:'apontar; salientar (informação)',separable:true,register:'neutral',freq:5,cls:'amber',ex:[{en:"He pointed out my mistake.",pt:"Ele apontou meu erro."},{en:"I'd like to point out that...",pt:"Gostaria de salientar que..."},{en:"She pointed it out to me.",pt:"Ela me chamou a atenção."}],trap:'Sentido figurado de salientar/destacar uma informação, não apenas apontar fisicamente.',similar:[{phrase:'highlight',meaning:'destacar'},{phrase:'emphasize',meaning:'enfatizar (formal)'}]},
  {id:'grow-up',phrase:'grow up',ipa:'ɡroʊ ʌp',meaning:'crescer; amadurecer',separable:false,register:'neutral',freq:5,cls:'sage',ex:[{en:"I grew up in São Paulo.",pt:"Cresci em São Paulo."},{en:"Grow up!",pt:"Cresce!"},{en:"Children grow up so fast.",pt:"Crianças crescem tão rápido."}],trap:'"Grow" (crescer fisicamente) ≠ "grow up" (passar pela infância/amadurecer).',similar:[{phrase:'mature',meaning:'amadurecer (formal)'},{phrase:'come of age',meaning:'atingir maioridade'}]},
  {id:'take-off',phrase:'take off',ipa:'teɪk ɔf',meaning:'decolar; tirar (roupa); deslanchar',separable:true,register:'neutral',freq:5,cls:'sage',ex:[{en:"The plane took off on time.",pt:"O avião decolou no horário."},{en:"Take off your shoes.",pt:"Tire os sapatos."},{en:"Her career took off.",pt:"A carreira dela deslanchou."}],trap:'Antônimo de "put on" para roupas. Para aviões, antônimo de "land".',similar:[{phrase:'remove',meaning:'remover (formal)'},{phrase:'depart',meaning:'partir (avião, formal)'}]},
  {id:'go-through',phrase:'go through',ipa:'ɡoʊ θru',meaning:'passar por (experiência); revisar',separable:false,register:'neutral',freq:5,cls:'amber',ex:[{en:"She went through a tough time.",pt:"Ela passou por um momento difícil."},{en:"Let's go through the report.",pt:"Vamos revisar o relatório."},{en:"He went through all his savings.",pt:"Ele gastou todas as economias."}],trap:'Sentido de "vivenciar" (experiência difícil) é muito comum e não literal.',similar:[{phrase:'experience',meaning:'experienciar (formal)'},{phrase:'review',meaning:'revisar'}]},
  {id:'get-back',phrase:'get back',ipa:'ɡɛt bæk',meaning:'voltar; recuperar',separable:true,register:'neutral',freq:5,cls:'sage',ex:[{en:"When did you get back?",pt:"Quando você voltou?"},{en:"I'll get back to you.",pt:"Eu retorno depois."},{en:"She got her job back.",pt:"Ela recuperou o emprego."}],trap:'"Get back to someone" = retornar contato. Comum em e-mail.',similar:[{phrase:'return',meaning:'retornar (formal)'},{phrase:'recover',meaning:'recuperar'}]},
  {id:'work-out',phrase:'work out',ipa:'wɝk aʊt',meaning:'dar certo; resolver; malhar',separable:true,register:'neutral',freq:5,cls:'sage',ex:[{en:"It all worked out in the end.",pt:"Tudo deu certo no final."},{en:"I work out three times a week.",pt:"Eu malho três vezes por semana."},{en:"Let's work out a plan.",pt:"Vamos elaborar um plano."}],trap:'Três sentidos distintos: dar certo, malhar, elaborar. Contexto é tudo.',similar:[{phrase:'figure out',meaning:'descobrir/sacar'},{phrase:'exercise',meaning:'exercitar-se (formal)'}]},
  {id:'come-on',phrase:'come on',ipa:'kʌm ɑn',meaning:'vamos lá!; ligar (luz, programa)',separable:false,register:'informal',freq:5,cls:'sage',ex:[{en:"Come on, let's go!",pt:"Vamos lá!"},{en:"The lights came on.",pt:"As luzes acenderam."},{en:"Come on, you can do it!",pt:"Vai lá, você consegue!"}],trap:'Interjeição de incentivo é o uso mais comum. Em texto formal, evite.',similar:[{phrase:"let's go",meaning:'vamos'},{phrase:'cheer up',meaning:'anime-se'}]},
  {id:'put-up',phrase:'put up',ipa:'pʊt ʌp',meaning:'erguer; hospedar; pendurar',separable:true,register:'neutral',freq:5,cls:'amber',ex:[{en:"They put up a new building.",pt:"Eles construíram um prédio novo."},{en:"Can you put me up for the night?",pt:"Pode me hospedar essa noite?"},{en:"She put up a poster.",pt:"Ela pendurou um pôster."}],trap:'"Put up with" (separado!) = tolerar. Muda o sentido completamente.',similar:[{phrase:'erect',meaning:'erguer (formal)'},{phrase:'host',meaning:'hospedar'}]},
  {id:'figure-out',phrase:'figure out',ipa:'ˈfɪɡjɚ aʊt',meaning:'descobrir; sacar; entender',separable:true,register:'informal',freq:5,cls:'sage',ex:[{en:"I can't figure it out.",pt:"Não consigo sacar."},{en:"Let's figure out a solution.",pt:"Vamos descobrir uma solução."},{en:"He figured out the puzzle.",pt:"Ele resolveu o quebra-cabeça."}],trap:'Mais informal que "find out" — usado para problemas/raciocínio, não fatos.',similar:[{phrase:'work out',meaning:'sacar/resolver'},{phrase:'understand',meaning:'entender (formal)'}]},
  {id:'take-over',phrase:'take over',ipa:'teɪk ˈoʊvɚ',meaning:'assumir; tomar (controle de)',separable:true,register:'neutral',freq:5,cls:'amber',ex:[{en:"She took over the company.",pt:"Ela assumiu a empresa."},{en:"Can you take over for me?",pt:"Pode me substituir?"},{en:"The new manager takes over Monday.",pt:"O novo gerente assume segunda."}],trap:'Comum em contexto corporativo (M&A): "company takeover" = aquisição.',similar:[{phrase:'assume control',meaning:'assumir controle (formal)'},{phrase:'replace',meaning:'substituir'}]},
  {id:'look-up',phrase:'look up',ipa:'lʊk ʌp',meaning:'consultar (dicionário); melhorar',separable:true,register:'neutral',freq:4,cls:'sage',ex:[{en:"Look it up in the dictionary.",pt:"Procure no dicionário."},{en:"Things are looking up.",pt:"As coisas estão melhorando."},{en:"Let me look up his number.",pt:"Deixa eu consultar o número dele."}],trap:'"Look up to someone" (com "to") = admirar alguém.',similar:[{phrase:'check',meaning:'verificar'},{phrase:'consult',meaning:'consultar (formal)'}]},
  {id:'turn-on',phrase:'turn on',ipa:'tɝn ɑn',meaning:'ligar (aparelho)',separable:true,register:'neutral',freq:4,cls:'sage',ex:[{en:"Turn on the TV.",pt:"Ligue a TV."},{en:"Turn it on.",pt:"Liga isso."},{en:"His friends turned on him.",pt:"Os amigos se voltaram contra ele."}],trap:'"Turn on someone" pode ser excitar OU virar-se contra. Contexto crítico.',similar:[{phrase:'switch on',meaning:'ligar (BrE)'},{phrase:'activate',meaning:'ativar (formal)'}]},
  {id:'turn-off',phrase:'turn off',ipa:'tɝn ɔf',meaning:'desligar; desinteressar',separable:true,register:'neutral',freq:4,cls:'sage',ex:[{en:"Turn off the lights.",pt:"Apague as luzes."},{en:"Turn it off, please.",pt:"Desliga, por favor."},{en:"His attitude turned me off.",pt:"A atitude dele me desanimou."}],trap:'"Turn-off" como substantivo = desinteresse.',similar:[{phrase:'switch off',meaning:'desligar (BrE)'},{phrase:'deactivate',meaning:'desativar (formal)'}]},
  {id:'come-from',phrase:'come from',ipa:'kʌm frʌm',meaning:'vir de; ser originário de',separable:false,register:'neutral',freq:5,cls:'sage',ex:[{en:"Where do you come from?",pt:"De onde você é?"},{en:"This wine comes from Chile.",pt:"Este vinho vem do Chile."},{en:"His ideas come from experience.",pt:"As ideias dele vêm da experiência."}],trap:'"Where do you come from?" = origem permanente. "Where are you from?" é sinônimo natural.',similar:[{phrase:'be from',meaning:'ser de (mais comum)'},{phrase:'originate',meaning:'originar-se (formal)'}]},
  {id:'come-down',phrase:'come down',ipa:'kʌm daʊn',meaning:'descer; cair (preço, temperatura)',separable:false,register:'neutral',freq:4,cls:'sage',ex:[{en:"Come down here!",pt:"Desça aqui!"},{en:"Prices came down.",pt:"Os preços caíram."},{en:"Come down to earth.",pt:"Volte à realidade."}],trap:'"Come down with" (com "with") = ficar doente.',similar:[{phrase:'descend',meaning:'descer (formal)'},{phrase:'drop',meaning:'cair'}]},
  {id:'set-out',phrase:'set out',ipa:'sɛt aʊt',meaning:'partir; propor-se a; estabelecer',separable:true,register:'neutral',freq:4,cls:'amber',ex:[{en:"They set out at dawn.",pt:"Partiram ao amanhecer."},{en:"He set out to break the record.",pt:"Ele se propôs a bater o recorde."},{en:"The contract sets out the terms.",pt:"O contrato estabelece os termos."}],trap:'Em contexto formal/jurídico ("contract sets out") tem sentido bem específico.',similar:[{phrase:'depart',meaning:'partir (formal)'},{phrase:'aim',meaning:'almejar'}]},
  {id:'go-down',phrase:'go down',ipa:'ɡoʊ daʊn',meaning:'descer; cair; ser bem/mal recebido',separable:false,register:'neutral',freq:5,cls:'sage',ex:[{en:"The temperature went down.",pt:"A temperatura caiu."},{en:"His joke didn't go down well.",pt:"A piada dele não foi bem recebida."},{en:"Go down to the basement.",pt:"Desça para o porão."}],trap:'"Go down well/badly" (com advérbio) = aceitação. Contexto idiomático.',similar:[{phrase:'decrease',meaning:'diminuir (formal)'},{phrase:'descend',meaning:'descer (formal)'}]},
  {id:'go-up',phrase:'go up',ipa:'ɡoʊ ʌp',meaning:'subir; aumentar',separable:false,register:'neutral',freq:5,cls:'sage',ex:[{en:"Prices keep going up.",pt:"Os preços continuam subindo."},{en:"Let's go up to the roof.",pt:"Vamos subir ao telhado."},{en:"Inflation went up 2%.",pt:"A inflação subiu 2%."}],trap:'Em finanças, mais usado que "increase" coloquialmente.',similar:[{phrase:'rise',meaning:'subir (formal)'},{phrase:'increase',meaning:'aumentar (formal)'}]},
  {id:'put-off',phrase:'put off',ipa:'pʊt ɔf',meaning:'adiar; desencorajar',separable:true,register:'neutral',freq:5,cls:'amber',ex:[{en:"Don't put off until tomorrow what you can do today.",pt:"Não deixe para amanhã o que pode fazer hoje."},{en:"The smell put me off.",pt:"O cheiro me desanimou."},{en:"Let's put it off.",pt:"Vamos adiar."}],trap:'Procrastinação clássica + sentido de "desanimar".',similar:[{phrase:'postpone',meaning:'adiar (formal)'},{phrase:'delay',meaning:'atrasar (formal)'}]},
  {id:'pick-out',phrase:'pick out',ipa:'pɪk aʊt',meaning:'escolher; identificar',separable:true,register:'neutral',freq:4,cls:'sage',ex:[{en:"Pick out a tie for me.",pt:"Escolha uma gravata pra mim."},{en:"I picked her out in the crowd.",pt:"Eu a identifiquei na multidão."},{en:"Pick out your favorite.",pt:"Escolha seu favorito."}],trap:'Conota seleção entre opções, não "pegar" (que é "pick up").',similar:[{phrase:'choose',meaning:'escolher'},{phrase:'select',meaning:'selecionar (formal)'}]},
  {id:'sit-down',phrase:'sit down',ipa:'sɪt daʊn',meaning:'sentar-se',separable:false,register:'neutral',freq:5,cls:'sage',ex:[{en:"Please sit down.",pt:"Por favor, sente-se."},{en:"Let's sit down and talk.",pt:"Vamos sentar e conversar."},{en:"Sit down, you're making me nervous.",pt:"Senta, você está me deixando nervoso."}],trap:'"Sit" sozinho é raro como imperativo — "sit down" é o natural.',similar:[{phrase:'take a seat',meaning:'tomar assento (educado)'},{phrase:'be seated',meaning:'sentar-se (muito formal)'}]},
  {id:'stand-up',phrase:'stand up',ipa:'stænd ʌp',meaning:'levantar-se; defender',separable:false,register:'neutral',freq:5,cls:'sage',ex:[{en:"Stand up, please.",pt:"Levante-se, por favor."},{en:"Stand up for what you believe.",pt:"Defenda o que acredita."},{en:"He stood me up.",pt:"Ele me deu um bolo."}],trap:'"Stand someone up" = dar bolo (encontro). Idiomatismo importante.',similar:[{phrase:'rise',meaning:'levantar-se (formal)'},{phrase:'get up',meaning:'levantar-se'}]},
  {id:'come-along',phrase:'come along',ipa:'kʌm əˈlɔŋ',meaning:'vir junto; progredir',separable:false,register:'neutral',freq:4,cls:'amber',ex:[{en:"Come along with us.",pt:"Venha com a gente."},{en:"How's the project coming along?",pt:"Como vai o projeto?"},{en:"A great opportunity came along.",pt:"Surgiu uma grande oportunidade."}],trap:'"How is X coming along?" = pergunta padrão sobre progresso. Muito útil.',similar:[{phrase:'progress',meaning:'progredir (formal)'},{phrase:'tag along',meaning:'acompanhar (informal)'}]},
  {id:'go-away',phrase:'go away',ipa:'ɡoʊ əˈweɪ',meaning:'ir embora; sumir',separable:false,register:'neutral',freq:5,cls:'sage',ex:[{en:"Go away!",pt:"Vai embora!"},{en:"My headache went away.",pt:"Minha dor de cabeça sumiu."},{en:"Let's go away for the weekend.",pt:"Vamos viajar no fim de semana."}],trap:'Pode ser viajar (turismo) ou simplesmente "sumir/desaparecer".',similar:[{phrase:'leave',meaning:'partir'},{phrase:'disappear',meaning:'desaparecer (formal)'}]},
  {id:'pass-away',phrase:'pass away',ipa:'pæs əˈweɪ',meaning:'falecer (eufemismo)',separable:false,register:'formal',freq:4,cls:'amber',ex:[{en:"My grandfather passed away last year.",pt:"Meu avô faleceu no ano passado."},{en:"She passed away peacefully.",pt:"Ela faleceu em paz."},{en:"He passed away at 90.",pt:"Ele faleceu aos 90."}],trap:'Eufemismo respeitoso para "die". "Die" é direto demais em conversas sensíveis.',similar:[{phrase:'pass on',meaning:'falecer (eufemismo)'},{phrase:'die',meaning:'morrer (direto)'}]},
  {id:'get-out',phrase:'get out',ipa:'ɡɛt aʊt',meaning:'sair; tirar (algo de)',separable:true,register:'neutral',freq:5,cls:'sage',ex:[{en:"Get out of here!",pt:"Saia daqui!"},{en:"Get the keys out of my bag.",pt:"Tire as chaves da minha bolsa."},{en:"How do we get out of this?",pt:"Como saímos dessa?"}],trap:'"Get out!" como exclamação de surpresa = "Não acredito!".',similar:[{phrase:'leave',meaning:'sair'},{phrase:'exit',meaning:'sair (formal)'}]},
  {id:'go-off',phrase:'go off',ipa:'ɡoʊ ɔf',meaning:'disparar (alarme); estragar (comida)',separable:false,register:'neutral',freq:4,cls:'amber',ex:[{en:"My alarm went off at 6.",pt:"Meu despertador tocou às 6."},{en:"The milk went off.",pt:"O leite estragou."},{en:"He went off without saying goodbye.",pt:"Ele saiu sem se despedir."}],trap:'Alarme "going off" é disparar/tocar (não desligar). Contraintuitivo.',similar:[{phrase:'sound',meaning:'tocar (alarme)'},{phrase:'spoil',meaning:'estragar'}]},
  {id:'sort-out',phrase:'sort out',ipa:'sɔrt aʊt',meaning:'resolver; organizar',separable:true,register:'neutral',freq:5,cls:'sage',ex:[{en:"Let me sort this out.",pt:"Deixa eu resolver isso."},{en:"We need to sort out our finances.",pt:"Precisamos organizar nossas finanças."},{en:"She'll sort it out.",pt:"Ela vai dar um jeito."}],trap:'Britanismo muito comum. Em AmE, "figure out" é alternativa.',similar:[{phrase:'resolve',meaning:'resolver (formal)'},{phrase:'organize',meaning:'organizar'}]},
  {id:'come-up-with',phrase:'come up with',ipa:'kʌm ʌp wɪð',meaning:'bolar; inventar (ideia, solução)',separable:false,register:'neutral',freq:5,cls:'sage',ex:[{en:"She came up with a great idea.",pt:"Ela bolou uma ótima ideia."},{en:"Can you come up with a name?",pt:"Pode pensar em um nome?"},{en:"He came up with the answer.",pt:"Ele encontrou a resposta."}],trap:'Não confunda com "come up" sozinho (surgir). A preposição muda o sentido.',similar:[{phrase:'devise',meaning:'criar (formal)'},{phrase:'think of',meaning:'pensar em'}]},
  {id:'go-ahead',phrase:'go ahead',ipa:'ɡoʊ əˈhɛd',meaning:'prosseguir; pode ir (permissão)',separable:false,register:'neutral',freq:5,cls:'sage',ex:[{en:"Go ahead, ask me.",pt:"Pode perguntar."},{en:"Let's go ahead with the plan.",pt:"Vamos prosseguir com o plano."},{en:"You go ahead, I'll catch up.",pt:"Vai indo, eu te alcanço."}],trap:'"Go ahead" como permissão é educado e comum. Substitui "you can".',similar:[{phrase:'proceed',meaning:'prosseguir (formal)'},{phrase:'continue',meaning:'continuar'}]},
  {id:'show-up',phrase:'show up',ipa:'ʃoʊ ʌp',meaning:'aparecer; comparecer',separable:false,register:'informal',freq:5,cls:'sage',ex:[{en:"He showed up late.",pt:"Ele apareceu atrasado."},{en:"Did anyone show up?",pt:"Alguém apareceu?"},{en:"She didn't show up.",pt:"Ela não apareceu."}],trap:'Mais informal que "appear" ou "arrive". Em contexto formal, evite.',similar:[{phrase:'arrive',meaning:'chegar'},{phrase:'turn up',meaning:'aparecer (BrE)'}]},
  {id:'bring-up',phrase:'bring up',ipa:'brɪŋ ʌp',meaning:'criar (filhos); mencionar',separable:true,register:'neutral',freq:5,cls:'amber',ex:[{en:"She brought up three kids.",pt:"Ela criou três filhos."},{en:"Don't bring that up again.",pt:"Não toque mais nesse assunto."},{en:"He brought up an important point.",pt:"Ele levantou um ponto importante."}],trap:'Dois sentidos comuns: criar filho OU trazer um assunto à tona.',similar:[{phrase:'raise',meaning:'criar/levantar (formal)'},{phrase:'mention',meaning:'mencionar'}]},
  {id:'take-out',phrase:'take out',ipa:'teɪk aʊt',meaning:'tirar; levar para fora; viajar com',separable:true,register:'neutral',freq:5,cls:'sage',ex:[{en:"Take out the trash.",pt:"Leve o lixo para fora."},{en:"He took her out for dinner.",pt:"Ele a levou para jantar."},{en:"Take it out of the box.",pt:"Tire da caixa."}],trap:'"Takeout" como substantivo = comida para viagem.',similar:[{phrase:'remove',meaning:'remover (formal)'},{phrase:'extract',meaning:'extrair (formal)'}]},
  {id:'put-down',phrase:'put down',ipa:'pʊt daʊn',meaning:'pousar; criticar; sacrificar (animal)',separable:true,register:'neutral',freq:4,cls:'amber',ex:[{en:"Put the gun down.",pt:"Abaixe a arma."},{en:"Don't put me down.",pt:"Não me menospreze."},{en:"They had to put the dog down.",pt:"Tiveram que sacrificar o cachorro."}],trap:'"Put-down" como substantivo = ofensa/menosprezo.',similar:[{phrase:'lower',meaning:'abaixar (formal)'},{phrase:'criticize',meaning:'criticar'}]},
  {id:'give-up',phrase:'give up',ipa:'ɡɪv ʌp',meaning:'desistir; abandonar (hábito)',separable:true,register:'neutral',freq:5,cls:'sage',ex:[{en:"Don't give up!",pt:"Não desista!"},{en:"I gave up smoking.",pt:"Parei de fumar."},{en:"She gave up her dream.",pt:"Ela abandonou o sonho."}],trap:'Brasileiros usam "abandon" (formal demais) ou "quit" (limitado). "Give up" é o natural.',similar:[{phrase:'quit',meaning:'parar/abandonar'},{phrase:'abandon',meaning:'abandonar (formal)'}]},
  {id:'come-over',phrase:'come over',ipa:'kʌm ˈoʊvɚ',meaning:'vir (visitar); passar a sentir-se',separable:false,register:'neutral',freq:5,cls:'sage',ex:[{en:"Come over for dinner.",pt:"Venha jantar (em casa)."},{en:"What came over you?",pt:"O que deu em você?"},{en:"I'll come over later.",pt:"Vou aí depois."}],trap:'Convite social comum. "Come over to my place" = "venha aqui em casa".',similar:[{phrase:'visit',meaning:'visitar'},{phrase:'drop by',meaning:'dar uma passada'}]},
  {id:'hold-on',phrase:'hold on',ipa:'hoʊld ɑn',meaning:'segurar; esperar; aguentar',separable:false,register:'neutral',freq:5,cls:'sage',ex:[{en:"Hold on a second.",pt:"Espera um segundo."},{en:"Hold on tight!",pt:"Segure firme!"},{en:"Hold on, don't give up.",pt:"Aguente firme, não desista."}],trap:'"Hold on" no telefone = "aguarde na linha". Uso muito comum.',similar:[{phrase:'wait',meaning:'esperar'},{phrase:'hang on',meaning:'esperar (informal)'}]},
  {id:'take-on',phrase:'take on',ipa:'teɪk ɑn',meaning:'assumir (responsabilidade); enfrentar',separable:true,register:'neutral',freq:5,cls:'amber',ex:[{en:"She took on the project.",pt:"Ela assumiu o projeto."},{en:"Don't take on too much.",pt:"Não se sobrecarregue."},{en:"He took on the champion.",pt:"Ele enfrentou o campeão."}],trap:'Em contexto corporativo, comum em descrições de cargo.',similar:[{phrase:'undertake',meaning:'assumir (formal)'},{phrase:'accept',meaning:'aceitar'}]},
  {id:'get-on',phrase:'get on',ipa:'ɡɛt ɑn',meaning:'entrar (transporte); dar-se bem',separable:false,register:'neutral',freq:5,cls:'sage',ex:[{en:"Get on the bus.",pt:"Entre no ônibus."},{en:"How are you getting on?",pt:"Como você está se saindo?"},{en:"They get on well.",pt:"Eles se dão bem."}],trap:'Para ônibus/trem/avião usa-se "get on", para carro "get in".',similar:[{phrase:'board',meaning:'embarcar (formal)'},{phrase:'get along',meaning:'dar-se bem'}]},
  {id:'get-off',phrase:'get off',ipa:'ɡɛt ɔf',meaning:'descer (transporte); livrar-se',separable:false,register:'neutral',freq:5,cls:'sage',ex:[{en:"Get off at the next stop.",pt:"Desça na próxima parada."},{en:"Get off my back!",pt:"Sai do meu pé!"},{en:"He got off easy.",pt:"Ele se safou fácil."}],trap:'Antônimo de "get on" para transportes. "Get out" para carro.',similar:[{phrase:'disembark',meaning:'desembarcar (formal)'},{phrase:'descend',meaning:'descer'}]},
  {id:'wake-up',phrase:'wake up',ipa:'weɪk ʌp',meaning:'acordar (do sono)',separable:true,register:'neutral',freq:5,cls:'sage',ex:[{en:"Wake up! It's 8 AM.",pt:"Acorda! São 8 da manhã."},{en:"I woke up at 6.",pt:"Acordei às 6."},{en:"Wake me up early.",pt:"Me acorde cedo."}],trap:'"Wake up" (acordar) ≠ "get up" (levantar). Você acorda primeiro, depois levanta.',similar:[{phrase:'awaken',meaning:'despertar (literário)'},{phrase:'rise',meaning:'levantar (formal)'}]},
  {id:'put-out',phrase:'put out',ipa:'pʊt aʊt',meaning:'apagar (fogo); divulgar',separable:true,register:'neutral',freq:4,cls:'amber',ex:[{en:"Put out the fire.",pt:"Apague o fogo."},{en:"He put out his hand.",pt:"Ele estendeu a mão."},{en:"They put out a statement.",pt:"Eles divulgaram um comunicado."}],trap:'Para luzes, "turn off" é mais comum. "Put out" é mais para fogo/cigarro.',similar:[{phrase:'extinguish',meaning:'extinguir (formal)'},{phrase:'release',meaning:'divulgar'}]},
  {id:'turn-around',phrase:'turn around',ipa:'tɝn əˈraʊnd',meaning:'virar-se; reverter situação',separable:true,register:'neutral',freq:4,cls:'amber',ex:[{en:"Turn around, please.",pt:"Vire-se, por favor."},{en:"They turned the company around.",pt:"Eles reverteram a empresa."},{en:"Turn it around.",pt:"Vire isso."}],trap:'"Turnaround" como substantivo = recuperação/reviravolta. Comum em business.',similar:[{phrase:'rotate',meaning:'rotacionar (formal)'},{phrase:'reverse',meaning:'reverter'}]},
  {id:'go-over',phrase:'go over',ipa:'ɡoʊ ˈoʊvɚ',meaning:'revisar; ser bem/mal recebido',separable:false,register:'neutral',freq:5,cls:'sage',ex:[{en:"Let's go over the plan.",pt:"Vamos revisar o plano."},{en:"His speech went over well.",pt:"O discurso dele foi bem recebido."},{en:"Go over the details.",pt:"Repasse os detalhes."}],trap:'"Go over" (revisar) é mais comum no profissional que "review".',similar:[{phrase:'review',meaning:'revisar (formal)'},{phrase:'examine',meaning:'examinar (formal)'}]},
  {id:'look-into',phrase:'look into',ipa:'lʊk ˈɪntu',meaning:'investigar; pesquisar (algo)',separable:false,register:'neutral',freq:5,cls:'sage',ex:[{en:"I'll look into it.",pt:"Vou investigar."},{en:"They're looking into the matter.",pt:"Estão investigando o assunto."},{en:"Look into your options.",pt:"Pesquise suas opções."}],trap:'"Look into" (investigar) ≠ "look at" (olhar) ≠ "look for" (procurar).',similar:[{phrase:'investigate',meaning:'investigar (formal)'},{phrase:'research',meaning:'pesquisar'}]},
  {id:'run-out',phrase:'run out',ipa:'rʌn aʊt',meaning:'acabar (estoque); ficar sem',separable:false,register:'neutral',freq:5,cls:'sage',ex:[{en:"We're running out of time.",pt:"Estamos ficando sem tempo."},{en:"The milk ran out.",pt:"O leite acabou."},{en:"I ran out of money.",pt:"Fiquei sem dinheiro."}],trap:'"Run out of X" = ficar sem X. Estrutura sempre com "of".',similar:[{phrase:'be out of',meaning:'estar sem'},{phrase:'deplete',meaning:'esgotar (formal)'}]},
  {id:'check-out',phrase:'check out',ipa:'ʧɛk aʊt',meaning:'conferir; sair (hotel)',separable:true,register:'neutral',freq:5,cls:'sage',ex:[{en:"Check out this video!",pt:"Confere esse vídeo!"},{en:"We checked out at noon.",pt:"Fizemos checkout ao meio-dia."},{en:"Check it out.",pt:"Dá uma olhada."}],trap:'Em hotel, "check-out" é substantivo. Verbal: "to check out".',similar:[{phrase:'examine',meaning:'examinar (formal)'},{phrase:'see',meaning:'ver (informal)'}]},
  {id:'check-in',phrase:'check in',ipa:'ʧɛk ɪn',meaning:'fazer check-in; reportar-se',separable:true,register:'neutral',freq:5,cls:'sage',ex:[{en:"Check in at the front desk.",pt:"Faça check-in na recepção."},{en:"I'll check in with you later.",pt:"Te dou notícias depois."},{en:"Check-in is at 3 PM.",pt:"O check-in é às 15h."}],trap:'Comum em viagens e contexto profissional ("check in with manager").',similar:[{phrase:'register',meaning:'registrar-se (formal)'},{phrase:'report',meaning:'reportar-se'}]},
  {id:'put-together',phrase:'put together',ipa:'pʊt təˈɡɛðɚ',meaning:'montar; juntar; preparar',separable:true,register:'neutral',freq:5,cls:'sage',ex:[{en:"Let's put together a plan.",pt:"Vamos montar um plano."},{en:"She put the puzzle together.",pt:"Ela montou o quebra-cabeça."},{en:"He put a team together.",pt:"Ele montou uma equipe."}],trap:'Conota construção ativa de algo. "Assemble" é mais formal.',similar:[{phrase:'assemble',meaning:'montar (formal)'},{phrase:'compile',meaning:'compilar'}]},
  {id:'break-down',phrase:'break down',ipa:'breɪk daʊn',meaning:'quebrar (máquina); chorar muito',separable:true,register:'neutral',freq:5,cls:'amber',ex:[{en:"My car broke down.",pt:"Meu carro quebrou."},{en:"She broke down in tears.",pt:"Ela desabou em lágrimas."},{en:"Let's break down the costs.",pt:"Vamos detalhar os custos."}],trap:'"Breakdown" como substantivo: detalhamento, colapso emocional, falha mecânica.',similar:[{phrase:'malfunction',meaning:'falhar (formal)'},{phrase:'analyze',meaning:'analisar'}]},
  {id:'break-up',phrase:'break up',ipa:'breɪk ʌp',meaning:'terminar (relacionamento); dispersar',separable:true,register:'neutral',freq:5,cls:'sage',ex:[{en:"They broke up last month.",pt:"Eles terminaram mês passado."},{en:"The crowd broke up.",pt:"A multidão se dispersou."},{en:"Break it up!",pt:"Parem com isso!"}],trap:'"Break up" para casais é o termo natural. "End the relationship" é formal.',similar:[{phrase:'split up',meaning:'separar-se'},{phrase:'separate',meaning:'separar (formal)'}]},
  {id:'hang-out',phrase:'hang out',ipa:'hæŋ aʊt',meaning:'passar tempo; curtir',separable:false,register:'informal',freq:5,cls:'sage',ex:[{en:"Let's hang out tonight.",pt:"Vamos sair hoje à noite."},{en:"They hang out at the mall.",pt:"Eles ficam no shopping."},{en:"I just want to hang out.",pt:"Só quero relaxar."}],trap:'Muito informal. Em contexto profissional, use "spend time with".',similar:[{phrase:'spend time',meaning:'passar tempo'},{phrase:'chill',meaning:'relaxar (informal)'}]},
  {id:'pass-out',phrase:'pass out',ipa:'pæs aʊt',meaning:'desmaiar; distribuir',separable:true,register:'neutral',freq:4,cls:'amber',ex:[{en:"He passed out from heat.",pt:"Ele desmaiou de calor."},{en:"She passed out flyers.",pt:"Ela distribuiu panfletos."},{en:"I almost passed out.",pt:"Quase desmaiei."}],trap:'Ambos sentidos são frequentes — contexto resolve.',similar:[{phrase:'faint',meaning:'desmaiar (formal)'},{phrase:'distribute',meaning:'distribuir (formal)'}]},
  {id:'put-back',phrase:'put back',ipa:'pʊt bæk',meaning:'devolver ao lugar; adiar',separable:true,register:'neutral',freq:4,cls:'sage',ex:[{en:"Put it back where you found it.",pt:"Coloque de volta onde achou."},{en:"They put back the meeting.",pt:"Adiaram a reunião."},{en:"Put the book back.",pt:"Recoloque o livro."}],trap:'Sentido literal mais comum. Para "adiar", "postpone" é alternativa.',similar:[{phrase:'return',meaning:'devolver (formal)'},{phrase:'replace',meaning:'recolocar'}]},
  {id:'come-across',phrase:'come across',ipa:'kʌm əˈkrɔs',meaning:'topar (acidentalmente); parecer (impressão)',separable:false,register:'neutral',freq:5,cls:'amber',ex:[{en:"I came across an old photo.",pt:"Topei com uma foto antiga."},{en:"He comes across as arrogant.",pt:"Ele parece arrogante."},{en:"How did I come across?",pt:"Que impressão eu passei?"}],trap:'"Come across as X" = "passar a impressão de X". Estrutura essencial em entrevistas.',similar:[{phrase:'encounter',meaning:'encontrar (formal)'},{phrase:'seem',meaning:'parecer'}]},
  {id:'fall-down',phrase:'fall down',ipa:'fɔl daʊn',meaning:'cair; desabar',separable:false,register:'neutral',freq:4,cls:'sage',ex:[{en:"The child fell down.",pt:"A criança caiu."},{en:"The building fell down.",pt:"O prédio desabou."},{en:"Don't fall down!",pt:"Não cai!"}],trap:'"Fall down" = cair ao chão. "Fall off" = cair de cima. "Fall over" = tombar.',similar:[{phrase:'collapse',meaning:'desabar (formal)'},{phrase:'tumble',meaning:'tombar'}]},
  {id:'cut-off',phrase:'cut off',ipa:'kʌt ɔf',meaning:'cortar (linha, suprimento); interromper',separable:true,register:'neutral',freq:4,cls:'amber',ex:[{en:"The call was cut off.",pt:"A ligação foi cortada."},{en:"Don't cut me off.",pt:"Não me interrompa."},{en:"They cut off the water supply.",pt:"Cortaram o fornecimento."}],trap:'"Cutoff" como substantivo = data limite ou ponto de corte.',similar:[{phrase:'interrupt',meaning:'interromper (formal)'},{phrase:'sever',meaning:'cortar (formal)'}]},
  {id:'go-after',phrase:'go after',ipa:'ɡoʊ ˈæftɚ',meaning:'perseguir; ir atrás (objetivo)',separable:false,register:'neutral',freq:4,cls:'amber',ex:[{en:"Go after your dreams.",pt:"Vá atrás dos seus sonhos."},{en:"The police went after him.",pt:"A polícia foi atrás dele."},{en:"She went after the promotion.",pt:"Ela foi atrás da promoção."}],trap:'Sentido figurado de buscar agressivamente. Mais forte que "pursue".',similar:[{phrase:'pursue',meaning:'perseguir (formal)'},{phrase:'chase',meaning:'perseguir'}]},
  {id:'come-about',phrase:'come about',ipa:'kʌm əˈbaʊt',meaning:'acontecer; ocorrer',separable:false,register:'formal',freq:3,cls:'amber',ex:[{en:"How did this come about?",pt:"Como isso aconteceu?"},{en:"The change came about gradually.",pt:"A mudança ocorreu gradualmente."},{en:"It came about by accident.",pt:"Aconteceu por acaso."}],trap:'Mais formal que "happen". Usado em escrita acadêmica.',similar:[{phrase:'occur',meaning:'ocorrer (formal)'},{phrase:'happen',meaning:'acontecer'}]},
  {id:'look-after',phrase:'look after',ipa:'lʊk ˈæftɚ',meaning:'cuidar de',separable:false,register:'neutral',freq:5,cls:'sage',ex:[{en:"Look after your sister.",pt:"Cuide da sua irmã."},{en:"Who looks after the dog?",pt:"Quem cuida do cachorro?"},{en:"Look after yourself.",pt:"Cuide-se."}],trap:'"Look after" (cuidar) é britânico-comum. Em AmE também usa "take care of".',similar:[{phrase:'take care of',meaning:'cuidar (AmE comum)'},{phrase:'tend',meaning:'cuidar (formal)'}]},
  {id:'take-care-of',phrase:'take care of',ipa:'teɪk kɛr ʌv',meaning:'cuidar de; resolver',separable:false,register:'neutral',freq:5,cls:'sage',ex:[{en:"I'll take care of it.",pt:"Eu cuido disso."},{en:"Take care of yourself.",pt:"Cuide-se."},{en:"She takes care of the kids.",pt:"Ela cuida das crianças."}],trap:'Duplo sentido: cuidar (pessoas) OU resolver (problema/tarefa).',similar:[{phrase:'look after',meaning:'cuidar (BrE)'},{phrase:'handle',meaning:'lidar com'}]},
  {id:'turn-up',phrase:'turn up',ipa:'tɝn ʌp',meaning:'aparecer; aumentar (volume)',separable:true,register:'neutral',freq:4,cls:'amber',ex:[{en:"He didn't turn up.",pt:"Ele não apareceu."},{en:"Turn up the music!",pt:"Aumenta o som!"},{en:"My keys turned up later.",pt:"Minhas chaves apareceram depois."}],trap:'Mais britânico que "show up". Para volume, sempre "turn up/down".',similar:[{phrase:'show up',meaning:'aparecer (AmE)'},{phrase:'increase',meaning:'aumentar (formal)'}]},
  {id:'show-off',phrase:'show off',ipa:'ʃoʊ ɔf',meaning:'exibir-se; ostentar',separable:false,register:'neutral',freq:4,cls:'amber',ex:[{en:"He's just showing off.",pt:"Ele só está se exibindo."},{en:"She showed off her new car.",pt:"Ela exibiu o carro novo."},{en:"Stop showing off!",pt:"Pare de se exibir!"}],trap:'"Show-off" como substantivo = pessoa exibida. Conotação geralmente negativa.',similar:[{phrase:'flaunt',meaning:'ostentar (formal)'},{phrase:'boast',meaning:'gabar-se'}]},
  {id:'add-up',phrase:'add up',ipa:'æd ʌp',meaning:'somar; fazer sentido',separable:true,register:'neutral',freq:4,cls:'amber',ex:[{en:"Add up these numbers.",pt:"Some esses números."},{en:"It doesn't add up.",pt:"Não faz sentido."},{en:"The story didn't add up.",pt:"A história não batia."}],trap:'"Doesn\'t add up" = "não fecha/não bate". Idiomatismo lógico.',similar:[{phrase:'sum up',meaning:'somar/resumir'},{phrase:'make sense',meaning:'fazer sentido'}]},
  {id:'count-on',phrase:'count on',ipa:'kaʊnt ɑn',meaning:'contar com (alguém)',separable:false,register:'neutral',freq:5,cls:'sage',ex:[{en:"You can count on me.",pt:"Pode contar comigo."},{en:"I count on him.",pt:"Eu conto com ele."},{en:"Don't count on it.",pt:"Não conte com isso."}],trap:'"Count on someone" = depender. "Count something" = contar números.',similar:[{phrase:'rely on',meaning:'confiar em (formal)'},{phrase:'depend on',meaning:'depender de'}]},
  {id:'go-with',phrase:'go with',ipa:'ɡoʊ wɪð',meaning:'combinar com; escolher',separable:false,register:'neutral',freq:5,cls:'sage',ex:[{en:"This wine goes with fish.",pt:"Esse vinho combina com peixe."},{en:"I'll go with the red one.",pt:"Vou escolher o vermelho."},{en:"It goes with the territory.",pt:"Faz parte do pacote."}],trap:'Para roupas/comida, "go with" = combinar. Para escolhas, "go with" = selecionar.',similar:[{phrase:'match',meaning:'combinar'},{phrase:'choose',meaning:'escolher'}]},
  {id:'take-up',phrase:'take up',ipa:'teɪk ʌp',meaning:'começar (hobby); ocupar (espaço)',separable:true,register:'neutral',freq:4,cls:'amber',ex:[{en:"I took up yoga.",pt:"Comecei a fazer ioga."},{en:"This takes up too much space.",pt:"Isso ocupa muito espaço."},{en:"He took up the offer.",pt:"Ele aceitou a oferta."}],trap:'Para hobbies novos é o termo natural.',similar:[{phrase:'begin',meaning:'começar (formal)'},{phrase:'occupy',meaning:'ocupar (formal)'}]},
  {id:'do-without',phrase:'do without',ipa:'du wɪˈðaʊt',meaning:'passar sem; dispensar',separable:false,register:'neutral',freq:3,cls:'amber',ex:[{en:"I can do without coffee.",pt:"Posso ficar sem café."},{en:"We did without TV for a year.",pt:"Ficamos sem TV por um ano."},{en:"I could do without his comments.",pt:"Dispenso os comentários dele."}],trap:'"Could do without" = expressar desagrado de modo educado.',similar:[{phrase:'manage without',meaning:'conseguir sem'},{phrase:'forgo',meaning:'abrir mão (formal)'}]},
  {id:'get-along',phrase:'get along',ipa:'ɡɛt əˈlɔŋ',meaning:'dar-se bem; conviver',separable:false,register:'neutral',freq:5,cls:'sage',ex:[{en:"They get along well.",pt:"Eles se dão bem."},{en:"How do you get along with him?",pt:"Como você se dá com ele?"},{en:"We get along fine.",pt:"A gente se entende bem."}],trap:'"Get along with" + pessoa. "Get on with" é o equivalente britânico.',similar:[{phrase:'get on with',meaning:'dar-se bem (BrE)'},{phrase:'be friends',meaning:'ser amigo'}]},
  {id:'put-away',phrase:'put away',ipa:'pʊt əˈweɪ',meaning:'guardar (no lugar)',separable:true,register:'neutral',freq:4,cls:'sage',ex:[{en:"Put away your toys.",pt:"Guarde seus brinquedos."},{en:"Put the dishes away.",pt:"Guarde a louça."},{en:"He put some money away.",pt:"Ele guardou um dinheiro."}],trap:'"Put money away" = poupar (sentido financeiro).',similar:[{phrase:'store',meaning:'armazenar (formal)'},{phrase:'save',meaning:'poupar/guardar'}]},
  {id:'turn-into',phrase:'turn into',ipa:'tɝn ˈɪntu',meaning:'transformar-se em; virar',separable:false,register:'neutral',freq:5,cls:'sage',ex:[{en:"It turned into a disaster.",pt:"Virou um desastre."},{en:"The frog turned into a prince.",pt:"O sapo virou príncipe."},{en:"He turned into a great leader.",pt:"Ele se tornou um grande líder."}],trap:'"Turn into" (transformação) ≠ "turn in to" (entregar a). Atenção ao espaço.',similar:[{phrase:'become',meaning:'tornar-se'},{phrase:'transform',meaning:'transformar (formal)'}]},
  {id:'look-out',phrase:'look out',ipa:'lʊk aʊt',meaning:'cuidado!; vigiar',separable:false,register:'neutral',freq:5,cls:'sage',ex:[{en:"Look out!",pt:"Cuidado!"},{en:"Look out for cars.",pt:"Preste atenção nos carros."},{en:"He's looking out for me.",pt:"Ele está olhando por mim."}],trap:'"Look out!" como interjeição é alerta de perigo.',similar:[{phrase:'watch out',meaning:'cuidado!'},{phrase:'be careful',meaning:'ter cuidado'}]},
  {id:'turn-down',phrase:'turn down',ipa:'tɝn daʊn',meaning:'recusar; abaixar (volume)',separable:true,register:'neutral',freq:4,cls:'amber',ex:[{en:"They turned down my offer.",pt:"Recusaram minha oferta."},{en:"Turn down the music.",pt:"Abaixa o som."},{en:"He turned the job down.",pt:"Ele recusou o emprego."}],trap:'Recusa formal de proposta. "Refuse" é mais direto, "turn down" mais elegante.',similar:[{phrase:'reject',meaning:'rejeitar (formal)'},{phrase:'decline',meaning:'declinar (formal)'}]},
  {id:'go-by',phrase:'go by',ipa:'ɡoʊ baɪ',meaning:'passar (tempo); guiar-se por',separable:false,register:'neutral',freq:5,cls:'sage',ex:[{en:"Time goes by quickly.",pt:"O tempo passa rápido."},{en:"Don't go by appearances.",pt:"Não se guie pelas aparências."},{en:"As time goes by...",pt:"À medida que o tempo passa..."}],trap:'Para tempo passando, sempre "go by". Quase nunca "pass" sozinho.',similar:[{phrase:'pass',meaning:'passar (formal)'},{phrase:'elapse',meaning:'transcorrer (formal)'}]},
  {id:'come-around',phrase:'come around',ipa:'kʌm əˈraʊnd',meaning:'recuperar consciência; mudar de opinião',separable:false,register:'neutral',freq:4,cls:'amber',ex:[{en:"He came around after surgery.",pt:"Ele recuperou consciência após a cirurgia."},{en:"She'll come around eventually.",pt:"Ela vai mudar de ideia eventualmente."},{en:"Come around for dinner.",pt:"Venha jantar."}],trap:'Três sentidos contextuais distintos.',similar:[{phrase:'regain consciousness',meaning:'recobrar consciência (formal)'},{phrase:'change mind',meaning:'mudar de ideia'}]},
  {id:'fill-out',phrase:'fill out',ipa:'fɪl aʊt',meaning:'preencher (formulário)',separable:true,register:'neutral',freq:5,cls:'sage',ex:[{en:"Fill out this form.",pt:"Preencha este formulário."},{en:"Fill it out, please.",pt:"Preencha, por favor."},{en:"She filled out the application.",pt:"Ela preencheu a inscrição."}],trap:'"Fill out" (AmE) ou "fill in" (BrE). Para formulários, ambos servem.',similar:[{phrase:'fill in',meaning:'preencher (BrE)'},{phrase:'complete',meaning:'completar (formal)'}]},
  {id:'fill-in',phrase:'fill in',ipa:'fɪl ɪn',meaning:'preencher; substituir (alguém)',separable:true,register:'neutral',freq:5,cls:'sage',ex:[{en:"Fill in the blanks.",pt:"Preencha as lacunas."},{en:"Can you fill in for me?",pt:"Pode me substituir?"},{en:"Fill me in on the details.",pt:"Me atualize sobre os detalhes."}],trap:'"Fill someone in" = atualizar alguém com informação. Idiomatismo profissional.',similar:[{phrase:'fill out',meaning:'preencher (AmE)'},{phrase:'substitute',meaning:'substituir (formal)'}]},
  {id:'come-by',phrase:'come by',ipa:'kʌm baɪ',meaning:'passar (visitar); conseguir',separable:false,register:'informal',freq:4,cls:'amber',ex:[{en:"Come by anytime.",pt:"Passa aí quando quiser."},{en:"How did you come by this?",pt:"Como você conseguiu isso?"},{en:"Good jobs are hard to come by.",pt:"Bons empregos são difíceis de achar."}],trap:'"Hard to come by" = difícil de encontrar. Idiomatismo de raridade.',similar:[{phrase:'drop by',meaning:'dar uma passada'},{phrase:'obtain',meaning:'obter (formal)'}]},
  {id:'see-off',phrase:'see off',ipa:'si ɔf',meaning:'despedir-se de (em viagem)',separable:true,register:'neutral',freq:3,cls:'amber',ex:[{en:"I'll see you off at the airport.",pt:"Vou te despedir no aeroporto."},{en:"They saw us off at the station.",pt:"Eles nos despediram na estação."},{en:"She came to see me off.",pt:"Ela veio se despedir de mim."}],trap:'Específico para despedida de viagem. Não é "say goodbye" genérico.',similar:[{phrase:'say goodbye',meaning:'despedir-se'},{phrase:'send off',meaning:'mandar embora'}]},
  {id:'come-up-against',phrase:'come up against',ipa:'kʌm ʌp əˈɡɛnst',meaning:'enfrentar (obstáculo)',separable:false,register:'neutral',freq:3,cls:'terra',ex:[{en:"We came up against several problems.",pt:"Enfrentamos vários problemas."},{en:"They came up against opposition.",pt:"Encontraram resistência."},{en:"She came up against a wall.",pt:"Ela bateu numa parede."}],trap:'Conota encontrar resistência inesperada. Mais forte que "encounter".',similar:[{phrase:'encounter',meaning:'encontrar (formal)'},{phrase:'face',meaning:'enfrentar'}]},
  {id:'go-into',phrase:'go into',ipa:'ɡoʊ ˈɪntu',meaning:'entrar em (carreira, detalhes)',separable:false,register:'neutral',freq:5,cls:'sage',ex:[{en:"She went into medicine.",pt:"Ela entrou para a medicina."},{en:"Don't go into details.",pt:"Não entre em detalhes."},{en:"Let's go into this further.",pt:"Vamos aprofundar isso."}],trap:'"Go into a career" = começar uma profissão. Comum em entrevistas/biografias.',similar:[{phrase:'enter',meaning:'entrar (formal)'},{phrase:'pursue',meaning:'buscar (carreira)'}]},
  {id:'put-through',phrase:'put through',ipa:'pʊt θru',meaning:'transferir (chamada); fazer passar por',separable:true,register:'neutral',freq:3,cls:'amber',ex:[{en:"I'll put you through.",pt:"Vou transferir sua ligação."},{en:"She put me through hell.",pt:"Ela me fez passar por um inferno."},{en:"Put me through to the manager.",pt:"Transfira para o gerente."}],trap:'Em telefonia corporativa, "put through" é o termo técnico.',similar:[{phrase:'transfer',meaning:'transferir (formal)'},{phrase:'connect',meaning:'conectar'}]},
  {id:'bring-back',phrase:'bring back',ipa:'brɪŋ bæk',meaning:'trazer de volta; relembrar',separable:true,register:'neutral',freq:5,cls:'sage',ex:[{en:"Bring back my book.",pt:"Traga meu livro de volta."},{en:"This brings back memories.",pt:"Isso traz lembranças."},{en:"They brought him back from retirement.",pt:"Trouxeram-no de volta da aposentadoria."}],trap:'"Brings back memories" = idiomatismo de nostalgia.',similar:[{phrase:'return',meaning:'devolver (formal)'},{phrase:'recall',meaning:'lembrar (formal)'}]},
  {id:'look-forward-to',phrase:'look forward to',ipa:'lʊk ˈfɔrwɚd tu',meaning:'estar ansioso por (algo)',separable:false,register:'neutral',freq:5,cls:'sage',ex:[{en:"I look forward to seeing you.",pt:"Estou ansioso para te ver."},{en:"We look forward to your reply.",pt:"Aguardamos sua resposta."},{en:"She's looking forward to the trip.",pt:"Ela está ansiosa pela viagem."}],trap:'Sempre "look forward TO + gerúndio (-ing)". Erro comum: "look forward to see" (errado).',similar:[{phrase:'anticipate',meaning:'antecipar (formal)'},{phrase:'eagerly await',meaning:'aguardar ansiosamente'}]},
  {id:'turn-in',phrase:'turn in',ipa:'tɝn ɪn',meaning:'entregar; ir dormir',separable:true,register:'neutral',freq:4,cls:'amber',ex:[{en:"Turn in your homework.",pt:"Entregue sua lição."},{en:"I'm going to turn in early.",pt:"Vou dormir cedo."},{en:"Turn the report in tomorrow.",pt:"Entregue o relatório amanhã."}],trap:'"Turn in" (entregar) é AmE-acadêmico. Em BrE, "hand in".',similar:[{phrase:'hand in',meaning:'entregar (BrE)'},{phrase:'submit',meaning:'submeter (formal)'}]},
  {id:'take-back',phrase:'take back',ipa:'teɪk bæk',meaning:'retirar (afirmação); devolver',separable:true,register:'neutral',freq:4,cls:'amber',ex:[{en:"Take it back!",pt:"Retire o que disse!"},{en:"I take back what I said.",pt:"Retiro o que falei."},{en:"Take this book back to the library.",pt:"Devolva este livro à biblioteca."}],trap:'"Take back words" = retratar-se. Muito comum em discussões.',similar:[{phrase:'retract',meaning:'retratar (formal)'},{phrase:'return',meaning:'devolver'}]},
  {id:'come-down-to',phrase:'come down to',ipa:'kʌm daʊn tu',meaning:'resumir-se a; depender de',separable:false,register:'neutral',freq:4,cls:'amber',ex:[{en:"It comes down to money.",pt:"Tudo se resume a dinheiro."},{en:"What it comes down to is...",pt:"O que importa é..."},{en:"It all comes down to one thing.",pt:"Tudo se reduz a uma coisa."}],trap:'"It comes down to" introduz a essência/conclusão.',similar:[{phrase:'boil down to',meaning:'resumir-se a'},{phrase:'reduce to',meaning:'reduzir a (formal)'}]},
  {id:'put-up-with',phrase:'put up with',ipa:'pʊt ʌp wɪð',meaning:'tolerar; aguentar',separable:false,register:'neutral',freq:5,cls:'amber',ex:[{en:"I can't put up with this anymore.",pt:"Não aguento mais isso."},{en:"She puts up with a lot.",pt:"Ela aguenta muita coisa."},{en:"Why do you put up with him?",pt:"Por que você aguenta ele?"}],trap:'Três palavras juntas — não pode separar. "Put up" sozinho tem outro sentido.',similar:[{phrase:'tolerate',meaning:'tolerar (formal)'},{phrase:'endure',meaning:'aguentar (formal)'}]}
];

